Archived calendars to obsidian Converting historic calendar events to Full Calendar in Obsidian 1. Convert ICS files to CSV Export ICS from from Calendar app Run convert_ICS File will export to: C:/Users/XXXXX/OneDrive/xfer/CALENDARS/COMPLETE ![[CONVERT_CVS.ipynb]] 2. Run convert_ics code pip install icalendar from datetime import datetime import csv import os import sys from icalendar import Calendar current_directory = os.getcwd() print(current_directory) # Path to the .ics file FILE_NAME = &quot;COURSES&quot; ics_file_path = f'{FILE_NAME}.ics' # Create a new CSV file csv_file_path = f'{FILE_NAME}.csv' csv_file = open(csv_file_path, 'w', newline='', encoding='utf-8') # Write the CSV header csv_writer = csv.writer(csv_file) csv_writer.writerow(['Subject', 'Start Time', 'End Time', 'Description','Location']) # Read the iCalendar file with open(f'C:/Users/XXXXX/OneDrive/xfer/CALENDARS/COMPLETE/ICS/{FILE_NAME}.ics', 'rb') as ics_file: cal = Calendar.from_ical(ics_file.read()) for event in cal.walk('VEVENT'): subject = event['SUMMARY'] start_time = event['DTSTART'].dt end_time = event['DTEND'].dt description = event['DESCRIPTION'] location = event['LOCATION'] csv_writer.writerow([subject, start_time, end_time, description, location]) # Close the CSV file csv_file.close() 3. Clean csv output (power query) USE TEMPLATE XLSX FILE! ![[CONVERSION_TEMPLATE_WORKING.xlsx]] Check errors (try --&gt; HasError = &quot;True&quot;) --&gt; automated power query file in /COMPLETE/WORKING_XLSX/ Replace value for TimeZone Start time and End time (-04:00 --&gt; +00:00) or (-05:00 --&gt; +00:00) Duplicate Start Time and End Time Split Start Time/End Time into START_DATE/START_TIME (Date Type) and END_DATE/END_TIME (time type) Export new csv file (for example, PSF2.csv) 4. Convert CSV to MD --&gt; Run CSV2MD code #FIELDS: Index, Subject, START_DATE, START_TIME, END_DATE, END_TIME, Description, Location import pandas as pd #from datetime import datetime import datetime as dt from datetime import datetime,date CAL_NAME=&quot;DSF&quot; tag_name=&quot;
- '#Nico'&quot; #How to export multiple tags? another 
? data = pd.read_csv(f'D:/xfer/CALENDARS/COMPLETE/CSV/{CAL_NAME}2.csv', delimiter=',') files = data.values.tolist() for file in files: index = file[0] subject = file[1] start_date = pd.to_datetime(file[2]).strftime(&quot;%Y-%m-%d&quot;) start_time = pd.to_datetime(file[3]).strftime(&quot;%H:%M&quot;) end_date = pd.to_datetime(file[4]).strftime(&quot;%Y-%m-%d&quot;) end_time = pd.to_datetime(file[5]).strftime(&quot;%H:%M&quot;) description = file[6] location = file[7] file_name = f'D:/xfer/CALENDARS/COMPLETE/CSV/{CAL_NAME}/{start_date}_{index}_{CAL_NAME}.md' with open(file_name, 'w', encoding='utf-8') as f: f.write(f'---
title: {subject}
date: {start_date}
startTime: {start_time}
completed: {end_date}
endTime: {end_time}
tags:{tag_name}
---
Index: {index}_{CAL_NAME}
Description: {description}
Location: {location}
') f.close() print(f'{file_name} saved.') ![[CSV2MD.ipynb]]
